20	// withOTelExport wraps the reporter with OTel telemetry export if configured.
21	func withOTelExport(rep reporter.Reporter, cfg *schema.SmokeConfig) reporter.Reporter {
22		if !cfg.OTel.Enabled {
23			return rep
24		}
25		exportURL := cfg.OTel.ExportURL
26		if exportURL == "" && cfg.OTel.JaegerURL != "" {
27			exportURL = cfg.OTel.JaegerURL + "/v1/traces"
28		}
29		if exportURL == "" {
30			return rep
31		}
32		if _, err := url.Parse(exportURL); err != nil {
33			fmt.Fprintf(os.Stderr, "warning: invalid otel export url: %v\n", err)
34			return rep
35		}
36		service := cfg.OTel.ServiceName
37		if service == "" {
38			service = cfg.Project
39		}
40		otel := reporter.NewOTelReporter(exportURL, service, cfg.OTel.ExportHeaders)
41		return reporter.NewMultiReporter(rep, otel)
42	}
43	
44	// withPushReport wraps the reporter with a PushReporter if --report-url is set.
45	func withPushReport(rep reporter.Reporter) reporter.Reporter {
46		if reportURL == "" {
