	var rep reporter.Reporter
	switch format {
	case "json":
		rep = reporter.NewJSON(os.Stdout)
	case "junit":
		rep = reporter.NewJUnit(os.Stdout)
	case "tap":
		rep = reporter.NewTAP(os.Stdout)
	case "prometheus":
		rep = reporter.NewPrometheus(os.Stdout)
	default:
		rep = reporter.NewTerminal(os.Stdout)
	}
	rep = withOTelExport(rep, cfg)

	// Parse timeout
	var timeoutDur time.Duration
	if timeout != "" {
		timeoutDur, err = time.ParseDuration(timeout)
		if err != nil {
			return fmt.Errorf("invalid timeout %q: %w", timeout, err)
		}
	}

	r := &runner.Runner{
		Config:    cfg,
		Reporter:  rep,
		ConfigDir: configDir,
	}

	runOnce := func() error {
		result, err := r.Run(runner.RunOptions{
			Tags:        tags,
			ExcludeTags: excludeTags,
			FailFast:    failFast,
			DryRun:      dryRun,
			Timeout:     timeoutDur,
		})
