268	func runWatch(configDir, configFile string, runOnce func() error) error {
269		// Run once immediately
270		if err := runOnce(); err != nil {
271			fmt.Fprintf(os.Stderr, "initial run error: %v\n", err)
272		}
273	
274		w, err := fsnotify.NewWatcher()
275		if err != nil {
276			return fmt.Errorf("fsnotify: %w", err)
277		}
278		defer w.Close()
279	
280		if err := w.Add(configDir); err != nil {
281			return fmt.Errorf("watching %s: %w", configDir, err)
282		}
283	
284		fmt.Fprintln(os.Stderr, "👀 watching", configDir, "(Ctrl+C to exit)")
285	
286		sigCh := make(chan os.Signal, 1)
287		signal.Notify(sigCh, os.Interrupt, syscall.SIGTERM)
288	
289		// Debounce: coalesce rapid events into a single re-run
290		debounce := 500 * time.Millisecond
291		var timer *time.Timer
292	
293		trigger := func() {
294			fmt.Fprintln(os.Stderr, "\n🔁 change detected, re-running…")
295			if err := runOnce(); err != nil {
296				fmt.Fprintf(os.Stderr, "run error: %v\n", err)
297			}
298		}
299	
300		for {
301			select {
302			case ev, ok := <-w.Events:
303				if !ok {
304					return nil
305				}
306				// Ignore chmod-only events
307				if !isRelevantEvent(ev.Op) {
308					continue
309				}
310				if timer != nil {
311					timer.Stop()
312				}
313				timer = time.AfterFunc(debounce, trigger)
314			case err, ok := <-w.Errors:
315				if !ok {
316					return nil
317				}
318				fmt.Fprintf(os.Stderr, "watch error: %v\n", err)
319			case <-sigCh:
320				fmt.Fprintln(os.Stderr, "\n✋ stopping watcher")
321				return nil
322			}
323		}
324	}
